async def _seed_hook(
    db,
    *,
    session_id: str,
    pid: int,
    received_at: float,
    source_system: str = "host",
    cwd: str = "/proj",
    event_name: str = "PreToolUse",
) -> None:
    payload = {
        "session_id": session_id,
        "hook_event_name": event_name,
        "pid": pid,
        "source_system": source_system,
        "cwd": cwd,
    }
    await schema.insert_log_hook(
        db,
        payload=payload,
        received_at=received_at,
        received_by="test",
    )
    await db.commit()


async def _seed_statusline(
    db,
    *,
    session_id: str,
    pid: int,
    received_at: float,
    source_system: str = "host",
    cwd: str = "/proj",
) -> None:
    payload = {
        "session_id": session_id,
        "pid": pid,
        "source_system": source_system,
        "cwd": cwd,
    }
    await schema.insert_log_statusline(
        db,
        payload=payload,
        received_at=received_at,
        received_by="test",
    )
    await db.commit()


async def _seed_death(
    db, *, pid: int, observed_at: float, source_system: str = "host", cwd: str = "/proj"
) -> None:
    await schema.insert_log_pid_death(
        db,
        pid=pid,
        source_system=source_system,
        cwd=cwd,
        observed_at=observed_at,
        observed_by="pid-watcher",
    )
    await db.commit()


class TestStatuslineOnlyEpoch:
    async def test_session_with_only_statusline_has_one_epoch(self, db) -> None:
        """database.md: a session can appear via statusline before any hook.
        Such a session is valid and has one epoch (alive)."""
        await _seed_statusline(db, session_id="s-only-sl", pid=4242, received_at=100.0)
        detail = await queries.get_session_by_id(db, session_id="s-only-sl")
        assert detail is not None
        assert len(detail["epochs"]) == 1
        epoch = detail["epochs"][0]
        assert epoch["pid"] == 4242
        assert epoch["started_at"] == 100.0
        assert epoch["ended_at"] is None  # alive

    async def test_session_with_statusline_then_hook_one_epoch(self, db) -> None:
        """Statusline arrives before first hook on the same pid → one epoch
        starting at the statusline's received_at."""
        await _seed_statusline(db, session_id="s1", pid=4242, received_at=50.0)
        await _seed_hook(db, session_id="s1", pid=4242, received_at=100.0)

        detail = await queries.get_session_by_id(db, session_id="s1")
        assert len(detail["epochs"]) == 1
        epoch = detail["epochs"][0]
        # Earliest activity is the statusline at 50.0
        assert epoch["started_at"] == 50.0


class TestEpochIdConsistency:
    async def test_session_detail_epoch_id_matches_idenricher(self, db) -> None:
        """The same (session_id, pid, source, cwd) epoch must hash to the
        same epoch_id whether computed via _epochs_for_session or IdEnricher.

        Setup: statusline at t=50 (earliest), hook at t=100.
        Both paths must use t=50 as earliest_received_at.
        """
        await _seed_statusline(db, session_id="s1", pid=4242, received_at=50.0)
        await _seed_hook(db, session_id="s1", pid=4242, received_at=100.0)

        detail = await queries.get_session_by_id(db, session_id="s1")
        epoch_id_from_detail = detail["epochs"][0]["epoch_id"]

        enricher = queries.IdEnricher(db)
        epoch_id_from_enricher = await enricher.epoch_id(
            session_id="s1", pid=4242, source_system="host", cwd="/proj"
        )

        assert epoch_id_from_detail == epoch_id_from_enricher

        # Also confirm both use the statusline's earlier timestamp
        expected = derive_epoch_id(
            session_id="s1",
            pid=4242,
            source_system="host",
            cwd="/proj",
            earliest_received_at=50.0,
        )
        assert epoch_id_from_detail == expected


class TestEndedAtFromPidDeath:
    async def test_closed_epoch_ended_at_matches_death(self, db) -> None:
        """Slice B added claude_log_pid_deaths. An epoch whose tuple has a
        death after its activity should report ended_at = death.observed_at.
        """
        await _seed_hook(db, session_id="s1", pid=4242, received_at=100.0)
        await _seed_death(db, pid=4242, observed_at=200.0)

        detail = await queries.get_session_by_id(db, session_id="s1")
        assert len(detail["epochs"]) == 1
        epoch = detail["epochs"][0]
        assert epoch["ended_at"] == 200.0

    async def test_alive_epoch_ended_at_is_none(self, db) -> None:
        await _seed_hook(db, session_id="s1", pid=4242, received_at=100.0)
        # No death recorded
        detail = await queries.get_session_by_id(db, session_id="s1")
        assert detail["epochs"][0]["ended_at"] is None

    async def test_resume_into_new_pid_first_epoch_closed(self, db) -> None:
        """Two epochs in a session via pid change. First epoch closed at
        the death (or activity gap if no death); second epoch alive."""
        await _seed_hook(db, session_id="s1", pid=10, received_at=100.0)
        await _seed_death(db, pid=10, observed_at=150.0)
        await _seed_hook(db, session_id="s1", pid=20, received_at=200.0)

        detail = await queries.get_session_by_id(db, session_id="s1")
        assert len(detail["epochs"]) == 2
        epochs_by_pid = {e["pid"]: e for e in detail["epochs"]}
        assert epochs_by_pid[10]["ended_at"] == 150.0
        assert epochs_by_pid[20]["ended_at"] is None


class TestSessionEpochsEndpoint:
    def test_endpoint_returns_epochs(self, client, db) -> None:
        from tests.conftest import run_async

        run_async(_seed_hook(db, session_id="sa", pid=10, received_at=100.0))
        run_async(_seed_hook(db, session_id="sa", pid=20, received_at=200.0))

        resp = client.get("/api/v2/sessions/sa/epochs")
        assert resp.status_code == 200
        body = resp.json()
        assert len(body) == 2
        pids = sorted(e["pid"] for e in body)
        assert pids == [10, 20]

    def test_endpoint_matches_session_detail_epochs(self, client, db) -> None:
        """Standalone endpoint must return the same data as session
        detail's nested epochs[]."""
        from tests.conftest import run_async

        run_async(_seed_hook(db, session_id="sa", pid=10, received_at=100.0))
        run_async(_seed_death(db, pid=10, observed_at=150.0))
        run_async(_seed_hook(db, session_id="sa", pid=20, received_at=200.0))

        detail_resp = client.get("/api/v2/sessions/sa")
        epochs_resp = client.get("/api/v2/sessions/sa/epochs")
        assert detail_resp.status_code == 200
        assert epochs_resp.status_code == 200
        assert detail_resp.json()["epochs"] == epochs_resp.json()

    def test_unknown_session_returns_404(self, client) -> None:
        resp = client.get("/api/v2/sessions/nope/epochs")
        assert resp.status_code == 404

    def test_session_with_only_statusline_endpoint(self, client, db) -> None:
        from tests.conftest import run_async

        run_async(
            _seed_statusline(db, session_id="sl-only", pid=4242, received_at=100.0)
        )
        resp = client.get("/api/v2/sessions/sl-only/epochs")
        assert resp.status_code == 200
        body = resp.json()
